(window.webpackJsonp=window.webpackJsonp||[]).push([[930],{882:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getSumAbsoluteDifferences = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=[<span class=\\"hljs-number\\">0</span>]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n        res[<span class=\\"hljs-number\\">0</span>]+=<span class=\\"hljs-built_in\\">Math</span>.abs(nums[i]-nums[<span class=\\"hljs-number\\">0</span>])\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;nums.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> l=i,r=nums.length-i\\n        <span class=\\"hljs-keyword\\">let</span> gap=nums[i]-nums[i<span class=\\"hljs-number\\">-1</span>]\\n        <span class=\\"hljs-keyword\\">let</span> last=res[res.length<span class=\\"hljs-number\\">-1</span>]\\n        res[res.length]=last+ gap*l - gap*r\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"sum-of-absolute-differences-in-a-sorted-array","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a <strong>\u975e\u9012\u51cf\xa0</strong>\u6709\u5e8f\u6574\u6570\u6570\u7ec4\xa0<code>nums</code>\xa0\u3002</p>\\n\\n<p>\u8bf7\u4f60\u5efa\u7acb\u5e76\u8fd4\u56de\u4e00\u4e2a\u6574\u6570\u6570\u7ec4<em>\xa0</em><code>result</code>\uff0c\u5b83\u8ddf<em>\xa0</em><code>nums</code>\xa0\u957f\u5ea6\u76f8\u540c\uff0c\u4e14<code>result[i]</code>\xa0\u7b49\u4e8e<em>\xa0</em><code>nums[i]</code>\xa0\u4e0e\u6570\u7ec4\u4e2d\u6240\u6709\u5176\u4ed6\u5143\u7d20\u5dee\u7684\u7edd\u5bf9\u503c\u4e4b\u548c\u3002</p>\\n\\n<p>\u6362\u53e5\u8bdd\u8bf4\uff0c\xa0<code>result[i]</code>\xa0\u7b49\u4e8e\xa0<code>sum(|nums[i]-nums[j]|)</code> \uff0c\u5176\u4e2d\xa0<code>0 <= j < nums.length</code> \u4e14\xa0<code>j != i</code>\xa0\uff08\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff09\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>nums = [2,3,5]\\n<b>\u8f93\u51fa\uff1a</b>[4,3,5]\\n<b>\u89e3\u91ca\uff1a</b>\u5047\u8bbe\u6570\u7ec4\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff0c\u90a3\u4e48\\nresult[0] = |2-2| + |2-3| + |2-5| = 0 + 1 + 3 = 4\uff0c\\nresult[1] = |3-2| + |3-3| + |3-5| = 1 + 0 + 2 = 3\uff0c\\nresult[2] = |5-2| + |5-3| + |5-5| = 3 + 2 + 0 = 5\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>nums = [1,4,6,8,10]\\n<b>\u8f93\u51fa\uff1a</b>[24,15,13,15,21]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 <= nums.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>1 <= nums[i] <= nums[i + 1] <= 10<sup>4</sup></code></li>\\n</ul>\\n","title":"1685. \u6709\u5e8f\u6570\u7ec4\u4e2d\u5dee\u7edd\u5bf9\u503c\u4e4b\u548c","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6570\u5b66"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1685"}')}}]);